// ─── 1. CORS Check ───────────────────────────────────────────────────────────
const input = $input.first().json;
const headers = input.headers || {};
const body    = input.body    || input;

const ALLOWED_ORIGINS = (process.env.FLORA_ALLOWED_ORIGINS || '').split(',').map(o => o.trim());
const origin = headers['origin'] || headers['Origin'] || '';

if (ALLOWED_ORIGINS.length && !ALLOWED_ORIGINS.includes(origin)) {
  // Log and block
  return [{ json: { blocked: true, status: 403, reason: 'cors', origin } }];
}

// ─── 2. Honeypot Check ───────────────────────────────────────────────────────
const honeypot = headers['x-flora-honeypot'] || body.honeypot || '';
if (honeypot !== '') {
  // Silent block — don't reveal to attacker
  return [{ json: { blocked: true, status: 403, reason: 'bot' } }];
}

// ─── 3. Token HMAC Validation ────────────────────────────────────────────────
const crypto = require('crypto');
const SECRET   = process.env.FLORA_HMAC_SECRET || '';
const TOKEN_TTL_HOURS = parseInt(process.env.FLORA_TOKEN_EXPIRY_HOURS || '2', 10);

const tokenHeader = headers['x-flora-token'] || '';
const [sessionId, timestamp, signature] = tokenHeader.split('.');

if (!sessionId || !timestamp || !signature) {
  return [{ json: { blocked: true, status: 401, reason: 'invalid_token', log: true, ip: headers['x-forwarded-for'] || '', sessionId: sessionId || '' } }];
}

const tokenAge = (Date.now() / 1000) - parseInt(timestamp, 10);
if (tokenAge > TOKEN_TTL_HOURS * 3600) {
  return [{ json: { blocked: true, status: 401, reason: 'invalid_token', log: true, ip: headers['x-forwarded-for'] || '', sessionId } }];
}

const expected = crypto.createHmac('sha256', SECRET).update(sessionId + '|' + timestamp).digest('hex');
if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected))) {
  return [{ json: { blocked: true, status: 401, reason: 'invalid_token', log: true, ip: headers['x-forwarded-for'] || '', sessionId } }];
}

// ─── 4. Cooldown Check ───────────────────────────────────────────────────────
const staticData = $getWorkflowStaticData('global');
if (!staticData.failedAuth) staticData.failedAuth = {};

const sessionFails = staticData.failedAuth[sessionId] || { count: 0, since: Date.now() };
const COOLDOWN_MS = 5 * 60 * 1000;
if (sessionFails.count >= 3 && (Date.now() - sessionFails.since) < COOLDOWN_MS) {
  return [{ json: { blocked: true, status: 429, reason: 'cooldown' } }];
}

// ─── 5. Rate Limit ───────────────────────────────────────────────────────────
const MAX_MSGS = parseInt(process.env.FLORA_RATE_LIMIT_MESSAGES || '20', 10);
const WINDOW_MS = parseInt(process.env.FLORA_RATE_LIMIT_WINDOW_HOURS || '1', 10) * 3600000;

if (!staticData.rateLimits) staticData.rateLimits = {};
const rl = staticData.rateLimits[sessionId] || { count: 0, since: Date.now() };

if ((Date.now() - rl.since) > WINDOW_MS) {
  rl.count = 0;
  rl.since = Date.now();
}
rl.count++;
staticData.rateLimits[sessionId] = rl;

if (rl.count > MAX_MSGS) {
  return [{ json: { blocked: true, status: 429, reason: 'rate_limit' } }];
}

// ─── 6. Image Size Check ─────────────────────────────────────────────────────
const MAX_IMAGE_MB = parseFloat(process.env.FLORA_MAX_IMAGE_SIZE_MB || '2');
if (body.image?.base64) {
  const bytes = (body.image.base64.length * 3) / 4;
  if (bytes > MAX_IMAGE_MB * 1024 * 1024) {
    return [{ json: { blocked: true, status: 413, reason: 'image_too_large' } }];
  }
}

// ─── 7. Input Sanitization ───────────────────────────────────────────────────
const MAX_LEN = parseInt(process.env.FLORA_MAX_MESSAGE_LENGTH || '1000', 10);
let message = body.message || '';

if (message.length > MAX_LEN) {
  message = message.slice(0, MAX_LEN);
}
// Strip HTML tags
message = message.replace(/<[^>]*>/g, '');
// Normalize unicode
message = message.normalize('NFC');

// ─── 8. Prompt Injection Filter ──────────────────────────────────────────────
const JAILBREAK_PATTERNS = [
  /ignore.*(?:previous|all|your).*instructions/i,
  /forget.*(?:everything|rules|system)/i,
  /you.*are.*now.*(?:DAN|evil|unrestricted)/i,
  /reveal.*(?:system|prompt|instructions|api|key)/i,
  /act.*as.*(?:if|though).*(?:no|without).*rules/i,
  /pretend.*(?:you|I).*(?:admin|developer|anthropic)/i,
  /bypass.*(?:safety|restrictions|filters)/i,
  /repeat.*(?:everything|all).*(?:above|before)/i,
  /what.*(?:is|are).*your.*(?:instructions|rules|prompt)/i,
  /translate.*(?:system|prompt).*to/i,
  /(?:sudo|admin|root).*mode/i,
  /disregard.*(?:all|previous)/i,
];

const isInjection = JAILBREAK_PATTERNS.some(p => p.test(message));
if (isInjection) {
  // Don't reveal detection — respond as if normal but redirect
  const lang = body.language || 'en';
  const safeReply = lang === 'es'
    ? 'Solo puedo ayudarte con plantas y pedidos. ¿En qué puedo ayudarte?'
    : 'I can only help you with plants and orders. How can I assist you?';
  return [{ json: { blocked: true, status: 200, reason: 'injection', safe_reply: safeReply } }];
}

// ─── All checks passed ────────────────────────────────────────────────────────
return [{ json: { blocked: false, sessionId, message, body: { ...body, message } } }];
